class Solution {
    isNStraightHand(hand, groupSize) {

        // If total cards can't be divided evenly, return false
        if (hand.length % groupSize !== 0) return false;

        // Store the frequency of each card
        const freq = new Map();
        for (let card of hand) {
            freq.set(card, (freq.get(card) || 0) + 1);
        }

        // Sort the keys to process from smallest
        const sortedKeys = [...freq.keys()].sort((a, b) => a - b);

        // Loop over each card in sorted order
        for (let card of sortedKeys) {
            let count = freq.get(card);

            // If current card already used up, skip
            if (count === 0) continue;

            // Try to form a group starting from this card
            for (let i = 0; i < groupSize; i++) {
                let nextCard = card + i;

                // If required card is missing or has insufficient frequency
                if ((freq.get(nextCard) || 0) < count) return false;

                // Decrease frequency
                freq.set(nextCard, freq.get(nextCard) - count);
            }
        }

        // All groups formed successfully
        return true;
    }
}

